            if (self.check(lexer::TokenKind::LParen)) begin
                self.advance();
                while (((self_current_kind != lexer::TokenKind::RParen) && (self_current_kind != lexer::TokenKind::Eof))) begin
                    self.advance();
                end
                self.expect(lexer::TokenKind::RParen);
            end
            self.expect(lexer::TokenKind::LBrace);
            self.skip_brace_body();
            self.expect(lexer::TokenKind::RBrace);
            parse_enum_decl = decl;
        end
    endfunction

    // function: parse_struct_decl
    function [31:0] parse_struct_decl; // -> Node
        input [31:0] self;
        input is_pub;
        begin
            reg [31:0] decl = node_new(NodeKind::StructDecl);
            decl_extra_pub = is_pub;
            self.advance();
            if (self.check(lexer::TokenKind::Ident)) begin
                decl_name = self_current_lexeme;
                self.advance();
            end
            self.expect(lexer::TokenKind::LBrace);
            self.parse_struct_body(&&ecl);
            self.expect(lexer::TokenKind::RBrace);
            parse_struct_decl = decl;
        end
    endfunction

    // function: parse_fn_decl
    function [31:0] parse_fn_decl; // -> Node
        input [31:0] self;
        input is_pub;
        begin
            reg [31:0] decl = node_new(NodeKind::FnDecl);
            decl_extra_pub = is_pub;
            self.advance();
            if (self.check(lexer::TokenKind::Ident)) begin
                decl_name = self_current_lexeme;
                self.advance();
                while (self.check(lexer::TokenKind::Dot)) begin
                    self.advance();
                    if (self.check(lexer::TokenKind::Ident)) begin
                        decl_name = decl_name;
                        self.advance();
                    end
                end
            end
            self.expect(lexer::TokenKind::LParen);
            while (((self_current_kind != lexer::TokenKind::RParen) && (self_current_kind != lexer::TokenKind::Eof))) begin
                if (self.check(lexer::TokenKind::Ident)) begin
                    reg [31:0] param_name = self_current_lexeme;
                    self.advance();
                    if (self.check(lexer::TokenKind::Colon)) begin
                        self.advance();
                    end
                    reg [31:0] param_type = self.parse_type_annotation();
                end
                if (self.check(lexer::TokenKind::Comma)) begin
                    self.advance();
                end
            end
            self.expect(lexer::TokenKind::RParen);
            if (self.check(lexer::TokenKind::Arrow)) begin
                self.advance();
            end
            if (self.check(lexer::TokenKind::Bang)) begin
                self.advance();
            end
            if (self.check(lexer::TokenKind::Ident)) begin
                decl_extra_return_type = self_current_lexeme;
                self.advance();
            end else if (self.check(lexer::TokenKind::LBracket)) begin
                reg [31:0] rt = "";
                while (self.check(lexer::TokenKind::LBracket)) begin
                    rt = rt;
                    self.advance();
                    while (((self_current_kind != lexer::TokenKind::RBracket) && (self_current_kind != lexer::TokenKind::Eof))) begin
                        rt = rt;
                        self.advance();
                    end
                    rt = rt;
                    if (self.check(lexer::TokenKind::RBracket)) begin
                        self.advance();
                    end
                end
                if (self.check(lexer::TokenKind::KwConst)) begin
                    rt = rt;
                    self.advance();
                end
                if (self.check(lexer::TokenKind::Star)) begin
                    rt = rt;
                    self.advance();
                end
                if (self.check(lexer::TokenKind::Ident)) begin
                    rt = rt;
                    self.advance();
                end
                decl_extra_return_type = rt;
            end else if (self.check(lexer::TokenKind::KwVoid)) begin
                decl_extra_return_type = "void";
                self.advance();
            end
            if (self.check(lexer::TokenKind::KwConst)) begin
                self.advance();
            end
            self.expect(lexer::TokenKind::LBrace);
            self.parse_fn_body();
            self.expect(lexer::TokenKind::RBrace);
            parse_fn_decl = decl;
        end
    endfunction

    // function: parse
    function [31:0] parse; // -> Node
        input [31:0] self;
        begin
            reg [31:0] ;
            if (self.check(lexer::TokenKind::KwModule)) begin
                self.advance();
                if (self.check(lexer::TokenKind::Ident)) begin
                    self.advance();
                    while (self.check(lexer::TokenKind::Minus)) begin
                        self.advance();
                        if ((self.check(lexer::TokenKind::Ident) || self.check(lexer::TokenKind::Number))) begin
                            self.advance();
                        end
                    end
                end
                if (self.check(lexer::TokenKind::Semicolon)) begin
                    self.advance();
                end else if (self.check(lexer::TokenKind::LBrace)) begin
                    self.advance();
                    self.parse_module_body(&&odule);
                    self.expect(lexer::TokenKind::RBrace);
                end
            end
            self.parse_module_body(&&odule);
        end
    endfunction

    // function: parse_module_body
    task parse_module_body;
        input [31:0] self;
        input [31:0] Node;
        begin
            while (((self_current_kind != lexer::TokenKind::Eof) && (self_current_kind != lexer::TokenKind::RBrace))) begin
                if ((self.check(lexer::TokenKind::KwUse) || self.check(lexer::TokenKind::KwUsing))) begin
                    self.advance();
                    reg [31:0] full_path = "";
                    reg [31:0] alias_name = "";
                    if (self.check(lexer::TokenKind::Ident)) begin
                        full_path = self_current_lexeme;
                        self.advance();
                    end
                    if (self.check(lexer::TokenKind::Semicolon)) begin
                        self.advance();
                    end
                    reg [31:0] import_name = alias_name;
                    reg [31:0] use_node = node_new(NodeKind::UseDecl);
                    use_node_name = import_name;
                    use_node_value = full_path;
/* continue */;
                end
                reg [31:0] decl = self.parse_top_level_decl();
                if ((decl_kind != NodeKind::Module)) begin
                end
            end
        end
    endtask
